INSERT INTO documents (section_slug, page_slug, title, content, updated_by)
VALUES (
  'affiliate',
  'partner-onboarding',
  'Partner Onboarding',
  $JSON${"type":"doc","content":[{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Partner Onboarding Workflow"}]},{"type":"paragraph","content":[{"type":"text","text":"Partner Application to First Commission. End-to-end process from affiliate application through compliance review, contract signing, portal access, tracking link generation, and first player referral."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Onboarding Flow — 6 Stages"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Stage 01 — Application & Initial Screening (SLA: 48 Hours)"}]},{"type":"paragraph","content":[{"type":"text","text":"Affiliate submits application · Automated pre-screen · Affiliate Manager triage"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Application Actions"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Affiliate completes the online application form: company name or individual name, website URL or social/digital channel, traffic sources (SEO, paid, social, influencer, community), target audience, estimated monthly player referral volume, and preferred commission structure"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Automated pre-screen runs immediately: check website URL against blacklisted domain list, verify the traffic source category is permitted under PAGCOR affiliate marketing guidelines, confirm the applicant is not on the AMLC blacklist or sanctions list"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Affiliate Manager receives the application and reviews within 48 hours. Checks: traffic quality, relevance to PH iGaming audience, channel authenticity (no fake follower signals), and absence of competing operator agreements that would create a conflict"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"If initial screening passes: send an acknowledgement email confirming receipt and a 48-hour review timeline"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"If initial screening fails: send a decline notification with the reason code (e.g. prohibited traffic source, non-PH audience, policy conflict) — do not give detailed rejection reasons that could be gamed"}]}]}]},{"type":"blockquote","content":[{"type":"paragraph","content":[{"type":"text","text":"PAGCOR Affiliate Marketing Rules: PAGCOR prohibits licensed operators from working with affiliates who target minors, use prohibited advertising channels (near schools, churches, or government buildings), or misrepresent the nature of gaming. Affiliate traffic sources must be documented and retained for PAGCOR audit purposes. Influencer and social media affiliates must comply with PAGCOR's responsible gambling messaging requirements in all content."}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Screening Outcomes"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Passes Screening: Advance to KYC / Compliance Review (Stage 2). Send acknowledgement with document requirements."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Pending — More Information: Traffic source unclear or volume claim requires verification. Request additional documentation (screenshots, analytics access, channel stats)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Declined: Prohibited channel, PAGCOR non-compliant content, or conflict of interest. Send decline with reason code. Log in CRM."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Stage 02 — KYC & Compliance Review (SLA: 5 Business Days)"}]},{"type":"paragraph","content":[{"type":"text","text":"Identity verification · AML check · PAGCOR compliance · BIR tax registration"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"KYC Requirements"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Individual affiliate: Government-issued ID (Philippine passport, driver's licence, UMID, SSS), proof of address (utility bill or bank statement within 90 days), selfie with ID, TIN (Tax Identification Number) from BIR"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Corporate affiliate: SEC registration certificate, BIR Certificate of Registration (COR), Articles of Incorporation, ID of authorised signatory, proof of business address, and bank details for commission payments"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"KYC Analyst runs PEP and sanctions screening on all individual signatories and beneficial owners. Any PEP match requires KYC Senior review before the affiliate agreement can be activated"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Verify that the affiliate's payment account (GCash, Maya, or bank) is registered in the same name as the KYC identity documents — mismatches must be resolved before commissions are ever paid"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"For corporate affiliates with majority foreign ownership: confirm whether a PAGCOR Special Affiliate Licence is required under current regulations"}]}]}]},{"type":"blockquote","content":[{"type":"paragraph","content":[{"type":"text","text":"BIR Tax Obligations: Affiliate commission payments in the Philippines are subject to withholding tax. Individual affiliates: 10% CWT (Creditable Withholding Tax) on commissions if registered professional, or 8% if under the 8% income tax option. Corporate affiliates: 2% EWT (Expanded Withholding Tax). The operator is responsible for withholding and remitting the correct tax to BIR. All affiliates must provide a valid TIN before the first commission payment is processed."}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Compliance Outcomes"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"KYC Approved: All documents verified, screening clear, TIN received. Advance to contract negotiation (Stage 3)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Pending Documents: Missing items. Send document checklist with 10-business-day response window. If no response: decline application."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"EDD Required: High-volume affiliate or PEP-adjacent. KYC Senior reviews. Source of funds declaration required for corporate affiliates expecting >\u20b1500k monthly commissions."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"KYC Failed: Forged documents, sanctions hit, or unresolvable mismatch. Decline. Log in compliance register. Do not re-engage."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Tools: KYC Case System, World-Check / ComplyAdvantage, BIR TIN Verification, SEC Business Registry"}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Stage 03 — Rate Negotiation & Contract (SLA: 5 Business Days)"}]},{"type":"paragraph","content":[{"type":"text","text":"Commission structure selection · Level assignment · Negative carryover policy · Contract signing"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Negotiation Process"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Affiliate Manager presents the standard rate card based on the affiliate's estimated monthly player volume and traffic quality tier"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Determine the commission structure: RevShare, CPA, or Hybrid. Hybrid structures require Head of Affiliates approval before presentation to the partner"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Assign the affiliate's starting level (L1 for all new direct partners). If the affiliate is being recruited by an existing L1/L2 partner as a sub-affiliate, assign the appropriate sub-level and ensure the total override chain does not breach the 65% margin cap"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Agree the negative carryover policy: whether a monthly negative NGR balance (operator loss from a player who wins more than they deposit) is carried forward and deducted from future earnings, or reset to zero each month. Default policy: negative carryover applies. This must be explicitly stated in the contract"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Agree the cookie window: the period during which a player referral is attributed to the affiliate after clicking a tracking link. Standard: 30 days last-click attribution. Premium partners: up to 90 days negotiable"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Affiliate Manager submits finalised terms to Legal for contract generation. Standard template used for L1\u2013L3. Custom contract required for L4\u2013L5 (approved by Head of Affiliates)"}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Key Contract Terms to Confirm"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Commission structure type and rate (RevShare %, CPA amount, or Hybrid combination)"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Level assignment (L1 direct or L2\u2013L5 sub-affiliate under named upline partner)"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Sub-affiliate recruitment rights — which downstream levels the partner is permitted to recruit"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Negative carryover policy: applies / does not apply. If applies: cap on maximum monthly carry (e.g. maximum 3 months carry before reset)"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Cookie window duration and attribution method (last-click)"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Minimum monthly payment threshold: commissions below \u20b1500 rolled to next month"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Payment method and schedule (monthly, within 15 days of month-end)"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Prohibited marketing practices per PAGCOR guidelines"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"BIR withholding tax rate and operator's responsibility to remit"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Termination, clawback, and fraud provisions"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Contract Signed: Digital signature via DocuSign or wet signature for corporate affiliates. Advance to portal setup (Stage 4)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Negotiation Pending: Affiliate requests non-standard terms. Affiliate Manager escalates to Head of Affiliates within 48h with recommendation."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Stage 04 — Portal Access & Tracking Link Generation (SLA: 24 Hours)"}]},{"type":"paragraph","content":[{"type":"text","text":"Affiliate portal account creation · Tracking link setup · Creative assets · First referral test"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Portal Setup Actions"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Create the affiliate's portal account within 24 hours of contract signing. Set commission structure, level, and rate configuration exactly as per the signed contract"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Generate unique tracking links with the affiliate's ID embedded. Create separate tracking links for each traffic source or campaign the affiliate runs (SEO landing page, Facebook ads, Viber group, TikTok — each should have a distinct link for attribution reporting)"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Set the cookie window duration in the tracking system to match the contracted period (30 or 90 days)"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"If the affiliate has a sub-affiliate who is also being onboarded simultaneously: link the sub-affiliate account in the portal under the correct upline hierarchy before generating tracking links"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Provide the affiliate with the creative asset library: banners (various sizes for web and mobile), social media templates, branded landing page access, and PAGCOR-compliant responsible gambling messaging inserts"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Conduct a test referral: have the affiliate click their tracking link and register a test account to confirm attribution is recording correctly in the portal before going live"}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Affiliate Portal Access Levels by Level"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"L1: Full portal access — player activity (anonymised), commission reports, sub-affiliate management, tracking link generator, creative library, payment history"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"L2: Standard access — own player activity, own commission reports, own tracking links, creative library. Can view (but not modify) sub-affiliate count if L3 recruitment is permitted"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"L3: Limited access — own player stats, own commission summary, own tracking links. No sub-affiliate management view by default"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"L4\u2013L5: Basic access — commission balance, tracking links, and payment history only. No sub-affiliate management unless explicitly enabled by Head of Affiliates"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Portal Live — Ready to Refer: Test referral confirmed. Tracking links distributed. Affiliate is live."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Stage 05 — Player Attribution & Commission Accrual (Ongoing · Monthly)"}]},{"type":"paragraph","content":[{"type":"text","text":"First click tracking · FTD qualification · RevShare accrual · CPA trigger logic"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Attribution Logic"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Cookie tracking: when a player clicks the affiliate's tracking link, a cookie is stored in their browser. If the player registers within the cookie window (30 or 90 days), the registration is attributed to that affiliate"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Last-click attribution: if a player clicks links from multiple affiliates, the last affiliate's link before registration takes credit. This is the standard model — first-click attribution may be negotiated for specific high-value partners on request"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"FTD qualification for CPA: a player qualifies for a CPA payment only when: (a) KYC is fully approved, (b) the player makes a first deposit of at least \u20b1500, and (c) the deposit is not reversed or charged back within 30 days"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"RevShare accrual: begins from the calendar month in which the player makes their first deposit. NGR is calculated monthly. Commission accrues continuously for as long as the player is active and the affiliate agreement is in force"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Negative NGR: if a player's monthly NGR is negative (operator pays out more than it receives), this negative amount is applied to the affiliate's account per the agreed negative carryover policy"}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Multi-Level Attribution Rules"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"A referred player is permanently attributed to the affiliate who generated the tracking link click that led to their registration — this attribution does not change even if the affiliate's level or rate changes later"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Override commissions cascade upward simultaneously in the same monthly processing run — upstream partners do not need to wait for downstream commissions to be paid first"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"If an affiliate is terminated, their direct player attributions remain active. Players continue to generate RevShare that is held by the operator. Pending commissions at termination are paid per the termination clause in the contract"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"If a player was referred by an affiliate who was later found to have engaged in fraud (fake traffic, self-referral), all commissions generated by that player referral are subject to clawback regardless of how far upstream the override chain goes"}]}]}]},{"type":"blockquote","content":[{"type":"paragraph","content":[{"type":"text","text":"GCash / Maya Attribution Note: Some PH players use GCash to register and deposit without clicking a tracked link (direct URL entry). Ensure the affiliate platform supports server-side tracking in addition to browser cookies, particularly for mobile-first players who use GCash's in-app browser, which may block third-party cookies. This is a common attribution gap in the PH market."}]}]}]}$JSON$::jsonb,
  'system'
)
ON CONFLICT (section_slug, page_slug) DO UPDATE
  SET title = EXCLUDED.title,
      content = EXCLUDED.content,
      updated_at = NOW(),
      updated_by = EXCLUDED.updated_by;
